26	/**
27	 * Acceptance test for stream-mode {@code reverse} on the Resequencer EIP.
28	 * Provided by the harness — implementations must make it pass unmodified.
29	 */
30	public class StreamResequencerReverseGateTest extends ContextTestSupport {
31	
32	    protected void sendBodyAndHeader(String endpointUri, final Object body, final Object seqno) {
33	        template.send(endpointUri, new Processor() {
34	            public void process(Exchange exchange) {
35	                Message in = exchange.getIn();
36	                in.setBody(body);
37	                in.setHeader("seqnum", seqno);
38	            }
39	        });
40	    }
41	
42	    @Test
43	    public void testStreamReverseDeliversDescendingSequenceOrder() throws Exception {
44	        getMockEndpoint("mock:result").expectedBodiesReceived("msg4", "msg3", "msg2", "msg1");
45	
46	        sendBodyAndHeader("direct:start", "msg2", 2L);
47	        sendBodyAndHeader("direct:start", "msg4", 4L);
48	        sendBodyAndHeader("direct:start", "msg1", 1L);
49	        sendBodyAndHeader("direct:start", "msg3", 3L);
50	
51	        assertMockEndpointsSatisfied();
52	    }
53	
54	    @Test
55	    public void testStreamReverseInOrderInputIsDeliveredReversed() throws Exception {
56	        getMockEndpoint("mock:result").expectedBodiesReceived("msg3", "msg2", "msg1");
57	
58	        sendBodyAndHeader("direct:start", "msg1", 1L);
59	        sendBodyAndHeader("direct:start", "msg2", 2L);
60	        sendBodyAndHeader("direct:start", "msg3", 3L);
61	
62	        assertMockEndpointsSatisfied();
63	    }
64	
65	    @Override
66	    protected RouteBuilder createRouteBuilder() {
67	        return new RouteBuilder() {
68	            @Override
69	            public void configure() {
70	                from("direct:start")
71	                        .resequence(header("seqnum")).stream().reverse()
72	                        .timeout(750)
73	                        .to("mock:result");
74	            }
75	        };
76	    }
77	}
