package org.apache.camel.processor.resequencer;

import org.apache.camel.Exchange;
import org.apache.camel.Expression;

/**
 * A {@link ExpressionResultComparator} that reverses the ordering of a delegate {@link ExpressionResultComparator} so
 * that a {@link org.apache.camel.processor.StreamResequencer} delivers elements in descending sequence order.
 * <p/>
 * Reversing the ordering only for {@link #compare(Exchange, Exchange)} is not enough for the stream resequencer: the
 * {@link org.apache.camel.processor.resequencer.ResequencerEngine} also relies on {@link #predecessor(Exchange, Exchange)}
 * and {@link #successor(Exchange, Exchange)} to detect gaps and to release elements without waiting for a timeout. Since
 * these two notions are direction-sensitive, they must be swapped in addition to inverting {@link #compare(Exchange, Exchange)}
 * so that the delegate's immediate-successor relation becomes the immediate-predecessor relation in the reversed
 * sequence, and vice versa.
 */
public class ReverseExpressionResultComparator implements ExpressionResultComparator {

    private final ExpressionResultComparator delegate;

    public ReverseExpressionResultComparator(ExpressionResultComparator delegate) {
        this.delegate = delegate;
    }

    @Override
    public void setExpression(Expression expression) {
        delegate.setExpression(expression);
    }

    @Override
    public boolean predecessor(Exchange o1, Exchange o2) {
        return delegate.successor(o1, o2);
    }

    @Override
    public boolean successor(Exchange o1, Exchange o2) {
        return delegate.predecessor(o1, o2);
    }

    @Override
    public int compare(Exchange o1, Exchange o2) {
        return delegate.compare(o2, o1);
    }

    @Override
    public boolean isValid(Exchange o1) {
        return delegate.isValid(o1);
    }

    @Override
    public String toString() {
        return "Reverse[" + delegate + "]";
    }
}

